export const generateA4PDF = (bets: number[][], title: string = "Relatório de Jogos") => {
  // @ts-ignore
  if (!window.jspdf) {
    alert("Biblioteca PDF não carregada. Tente recarregar a página.");
    return;
  }

  // @ts-ignore
  const { jsPDF } = window.jspdf;

  // Configuração A4 Landscape (Deitado)
  // Largura: 297mm, Altura: 210mm
  const doc = new jsPDF({
    orientation: 'landscape',
    unit: 'mm',
    format: 'a4'
  });

  const pageWidth = 297;
  const pageHeight = 210;

  // --- DIMENSÕES BASEADAS NA IMAGEM TÉCNICA (VOLANTE CAIXA) ---
  const slipWidth = 81;   // Largura exata do volante
  const slipHeight = 187; // Altura exata do volante (linha de corte)

  // Layout na página A4 (3 volantes lado a lado)
  const numCols = 3;
  // Margem esquerda para centralizar: (297 - (81 * 3)) / 2 = 27mm
  const marginLeft = (pageWidth - (slipWidth * numCols)) / 2;
  // Margem superior para centralizar: (210 - 187) / 2 = 11.5mm
  const marginTop = (pageHeight - slipHeight) / 2;

  // Configurações de Jogos por Volante
  const gamesPerSlip = 3; 
  // O volante oficial tem 3 áreas de jogo
  // Game 1 ~ Y=35mm, Game 2 ~ Y=85mm, Game 3 ~ Y=135mm (Aproximado para caber no layout de 187mm)

  const totalBets = bets.length;
  // Quantos volantes precisamos?
  const totalSlipsNeeded = Math.ceil(totalBets / gamesPerSlip);
  // Quantas páginas A4? (3 volantes por página)
  const totalPages = Math.ceil(totalSlipsNeeded / numCols);

  let currentBetIndex = 0;

  for (let p = 0; p < totalPages; p++) {
    if (p > 0) doc.addPage();

    // Desenhar até 3 volantes nesta página
    for (let c = 0; c < numCols; c++) {
      // Se já processamos todas as apostas, parar
      if (currentBetIndex >= totalBets) break;

      const xBase = marginLeft + (c * slipWidth);
      const yBase = marginTop;

      // Coletar as apostas para ESTE volante (max 3)
      const slipBets: number[][] = [];
      for (let k = 0; k < gamesPerSlip; k++) {
        if (currentBetIndex < totalBets) {
          slipBets.push(bets[currentBetIndex]);
          currentBetIndex++;
        }
      }

      // --- DESENHAR O VOLANTE COMPLETO ---
      drawOfficialVolante(doc, xBase, yBase, slipWidth, slipHeight, slipBets);

      // --- LINHA DE CORTE (PONTILHADA ESCURA) ---
      doc.setDrawColor(100, 100, 100); 
      doc.setLineWidth(0.2);
      doc.setLineDash([2, 2], 0);
      doc.rect(xBase, yBase, slipWidth, slipHeight);
      doc.setLineDash([]); // Reset
    }
  }

  doc.save(`volantes_padrao_caixa_${new Date().getTime()}.pdf`);
};

/**
 * Desenha um único volante com o layout oficial da Caixa
 */
const drawOfficialVolante = (
  doc: any, 
  x: number, 
  y: number, 
  w: number, 
  h: number, 
  bets: number[][]
) => {
  // Cores
  const colorText = [100, 100, 100]; // Cinza médio para textos
  const colorMark = [0, 0, 0];       // Preto para marcação (leitura)
  const colorLine = [200, 200, 200]; // Cinza claro para linhas divisórias

  // 1. CABEÇALHO (Simulado)
  // Área aprox: 28mm de altura (baseado na imagem)
  const headerHeight = 28;

  // Fundo do cabeçalho (apenas ilustrativo, verde bem suave ou branco)
  // doc.setFillColor(240, 255, 240);
  // doc.rect(x, y, w, headerHeight, 'F');

  doc.setTextColor(40, 110, 60); // Verde Mega-Sena
  doc.setFont("helvetica", "bold");
  doc.setFontSize(18);
  doc.text("mega-sena", x + (w / 2), y + 15, { align: 'center' });

  doc.setFontSize(6);
  doc.setTextColor(...colorText);
  doc.text("MARQUE NO QUADRO ABAIXO", x + (w/2), y + 24, { align: 'center' });

  // 2. ÁREAS DE JOGO (3 Jogos)
  // Altura de cada bloco de jogo ~ 45mm
  // Espaçamento vertical
  const startY_Game1 = y + 28; // Começa logo após o cabeçalho
  const gameBlockHeight = 44; // Altura de cada matriz de 60 números
  const gapBetweenGames = 6;  // Espaço entre jogos

  // Posições Y dos 3 jogos
  const gamePositionsY = [
    startY_Game1,
    startY_Game1 + gameBlockHeight + gapBetweenGames,
    startY_Game1 + (gameBlockHeight + gapBetweenGames) * 2
  ];

  // Desenhar cada bloco de jogo
  gamePositionsY.forEach((gameY, index) => {
    // Linha divisória fina acima do jogo 2 e 3
    if (index > 0) {
      doc.setDrawColor(...colorLine);
      doc.setLineWidth(0.1);
      doc.line(x + 5, gameY - (gapBetweenGames/2), x + w - 5, gameY - (gapBetweenGames/2));
    }

    const bet = bets[index] || []; // Aposta atual ou vazia
    drawGameGrid(doc, x, gameY, w, gameBlockHeight, bet);
  });

  // 3. QR CODE (Rodapé)
  // Colocamos o QR code na parte inferior
  const qrAreaY = y + h - 22; // 22mm do fim
  const qrSize = 18;
  const qrX = x + w - qrSize - 4; // Alinhado à direita

  if (bets.length > 0) {
    drawQRCode(doc, bets, qrX, qrAreaY, qrSize);

    // Texto descritivo ao lado do QR
    doc.setFontSize(6);
    doc.setTextColor(80, 80, 80);
    doc.text("Apostas geradas:", x + 4, qrAreaY + 4);
    bets.forEach((b, i) => {
        const txt = `J${i+1}: ${b.map(n=>String(n).padStart(2,'0')).join('-')}`;
        doc.text(txt, x + 4, qrAreaY + 8 + (i * 3));
    });
  }

  // Logo Caixa (Simulado texto)
  doc.setFont("helvetica", "bold");
  doc.setFontSize(10);
  doc.setTextColor(40, 60, 120); // Azul Caixa
  doc.text("loterias CAIXA", x + 4, y + h - 3);
};

/**
 * Desenha a grade de 60 números + Marcas de Sincronismo (Timing Marks)
 */
const drawGameGrid = (
  doc: any,
  x: number,
  y: number,
  w: number,
  h: number,
  selectedNumbers: number[]
) => {
  const selectedSet = new Set(selectedNumbers);

  // Configurações Geométricas
  const leftMargin = 8; // Espaço para timing marks
  const rightMargin = 2;
  const gridWidth = w - leftMargin - rightMargin;

  const rows = 6;
  const cols = 10;

  const cellW = gridWidth / cols;
  const cellH = h / rows;

  // Timing Marks (Barra Preta na Lateral Esquerda)
  // Devem alinhar com o centro de cada linha
  const timingMarkW = 4; // Largura da barra preta
  const timingMarkH = 2.5; // Altura da barra preta
  const timingX = x + 2; // Posição X da barra

  // Configuração da Fonte dos Números (Cinza)
  doc.setFont("courier", "normal"); // Fonte monoespaçada ou helvetica
  doc.setFontSize(7);
  doc.setTextColor(180, 180, 180); // Cinza bem claro para o fundo

  // Tamanho do retângulo de marcação (Preto)
  const markW = 5.5;
  const markH = 3.0;

  for (let r = 0; r < rows; r++) {
    const rowY = y + (r * cellH);
    const centerY = rowY + (cellH / 2);

    // 1. DESENHAR TIMING MARK (Preto Absoluto)
    doc.setFillColor(0, 0, 0);
    doc.rect(timingX, centerY - (timingMarkH / 2), timingMarkW, timingMarkH, 'F');

    // 2. DESENHAR NÚMEROS DA LINHA
    for (let c = 0; c < cols; c++) {
      const num = (r * 10) + (c + 1);
      const numStr = String(num).padStart(2, '0');

      const cellX = x + leftMargin + (c * cellW);
      const centerX = cellX + (cellW / 2);

      // Texto de fundo: [01]
      // Desenhamos o texto centralizado
      // Adicionamos colchetes para imitar o volante
      doc.setTextColor(150, 150, 150);
      doc.text(`[${numStr}]`, centerX, centerY + 1, { align: 'center' });

      // Se o número estiver selecionado, desenhar o retângulo PRETO por cima
      if (selectedSet.has(num)) {
        doc.setFillColor(0, 0, 0);
        doc.rect(
          centerX - (markW / 2),
          centerY - (markH / 2) + 0.5, // Leve ajuste visual
          markW,
          markH,
          'F'
        );
      }
    }
  }
};

/**
 * Gera e desenha o QR Code contendo os dados das apostas
 */
const drawQRCode = (doc: any, bets: number[][], x: number, y: number, size: number) => {
    try {
        // @ts-ignore
        const typeNumber = 0; // Auto detection
        // @ts-ignore
        const errorCorrectionLevel = 'L';
        // @ts-ignore
        const qr = qrcode(typeNumber, errorCorrectionLevel);

        // Dados para o QR: Simples texto com os jogos
        const data = bets.map(b => b.join(',')).join(';');
        qr.addData(data);
        qr.make();

        // Criar imagem base64 do QR
        // Cell size calculado para caber no tamanho desejado
        const cellSize = Math.floor(size / qr.getModuleCount());
        const imgData = qr.createDataURL(4); // margin 4

        doc.addImage(imgData, 'GIF', x, y, size, size);
    } catch (e) {
        console.error("Erro ao gerar QR Code", e);
        // Fallback se a lib falhar
        doc.rect(x, y, size, size);
        doc.setFontSize(6);
        doc.text("QR Error", x, y + size/2);
    }
};
